class Solution:
    def maxPathSum(self, root) -> int:
        self.best = float("-inf")    # 全局最大路径和(可不经过根)

        def gain(n):                 # 返回「从 n 向下走一条边能贡献的最大增益」
            if not n:
                return 0
            l = max(0, gain(n.left)) # 子树增益为负就当 0(不要这条)
            r = max(0, gain(n.right))
            self.best = max(self.best, n.val + l + r)  # 以 n 为「拐点」的完整路径和
            return n.val + max(l, r) # 向上只能选左右其一(路径不能分叉)

        gain(root)
        return self.best
